const retryOperation = (
  operation: (attempt) => T,
  maxAttempts,
  delayMs
): Promise<T> => {
  return new Promise((resolve, reject) => {
    const attempt = (currentAttempt) => {
      try {
        const result = operation(currentAttempt);
        resolve(result);
      } catch (error) {
        if (currentAttempt >= maxAttempts) {
          reject(error);
        } else {
          setTimeout(() => attempt(currentAttempt + 1), delayMs);
        }
      }
    };
    attempt(1);
  });
};

